using System;
using System.Collections.Generic;
using System.ComponentModel;
using System.Data;
using System.Drawing;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using System.Windows.Forms;
using System.IO;
using ClosedXML.Excel;

namespace WeldMonitor3
{
    public partial class _FrmSearch : Form
    {
        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
             int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
             int nWidthEllipse, int nHeightEllipse);
        public _FrmSearch()
        {
            InitializeComponent();
            ThemeManager.ApplyDarkTheme(this);
            ApplyLanguage();
            StyleControls();
        }
        private void StyleControls()
        {
            this.BackColor = pColor.Theme.backColor;

            // 패널들 배경 흰색 적용
            Panel[] panels = { panel2 };
            foreach (var pnl in panels)
                pnl.BackColor = pColor.Theme.panelColor;

            // 버튼 스타일 통일화
            foreach (var ctrl in panel2.Controls)
            {
                if (ctrl is Button btn)
                {
                    btn.BackColor = pColor.Theme.buttonColor;
                    btn.ForeColor = pColor.Theme.buttonText;
                    btn.FlatStyle = FlatStyle.Flat;
                    btn.FlatAppearance.BorderSize = 0;
                    // 둥근 모서리

                    btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 15, 15));

                    // 호버 효과
                    btn.MouseEnter += (s, e) => btn.BackColor = pColor.Theme.buttonHover;
                    btn.MouseLeave += (s, e) => btn.BackColor = pColor.Theme.buttonColor;
                }
            }
        }
        private List<string> FindAllCsvFiles(DateTime startDate, DateTime endDate)
        {
            string baseDir = GlobalValues.GetDataPath();
            List<string> resultFiles = new List<string>();

            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
            {
                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
                if (!Directory.Exists(folder)) continue;

                string[] files = Directory.GetFiles(folder, "*.csv");
                resultFiles.AddRange(files);
            }

            return resultFiles;
        }
        private DataTable LoadCsvDataToTable(List<string> files)
        {
            DataTable table = new DataTable();

            bool headerRead = false;

            foreach (var file in files)
            {
                using (StreamReader reader = new StreamReader(file, Encoding.UTF8))
                {
                    string headerLine = reader.ReadLine();
                    if (headerLine == null) continue;

                    string[] headers = headerLine.Split(',');

                    if (!headerRead)
                    {
                        foreach (var h in headers)
                            table.Columns.Add(h);
                        headerRead = true;
                    }

                    while (!reader.EndOfStream)
                    {
                        string line = reader.ReadLine();
                        if (string.IsNullOrWhiteSpace(line)) continue;

                        string[] values = line.Split(',');
                        table.Rows.Add(values);
                    }
                }
            }

            return table;
        }
        private async void btnSearch_Click(object sender, EventArgs e)
        {
            DateTime startDate = dateTimePickerStart.Value.Date;
            DateTime endDate = dateTimePickerEnd.Value.Date;

            List<string> csvFiles = FindAllCsvFiles(startDate, endDate);
            if (csvFiles.Count == 0)
            {
                MessageBox.Show(this, LanguageManager.Get("msg_no_csv_found_date"), LanguageManager.Get("msg_no_data"), MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            dataGridView1.Rows.Clear();
            dataGridView1.Columns.Clear();

            string[] headers = null;

            foreach (string file in csvFiles)
            {
                using (var reader = new StreamReader(file))
                {
                    string headerLine = await reader.ReadLineAsync();
                    if (headerLine == null) continue;

                    // 최초 1회 헤더 세팅
                    if (headers == null)
                    {
                        headers = headerLine.Split(',');

                        dataGridView1.Columns.Add("Info", "File");
                        for (int i = 0; i < headers.Length; i++)
                            dataGridView1.Columns.Add("Col" + i.ToString(), headers[i]);
                    }

                    // 파일명 한 줄 출력
                    string fileNameOnly = Path.GetFileName(file);
                    object[] fileNameRow = new object[dataGridView1.Columns.Count];
                    fileNameRow[0] = fileNameOnly;
                    dataGridView1.Rows.Add(fileNameRow);

                    // 데이터 출력
                    while (!reader.EndOfStream)
                    {
                        string line = await reader.ReadLineAsync();
                        if (string.IsNullOrWhiteSpace(line)) continue;

                        string[] tokens = line.Split(',');
                        object[] row = new object[dataGridView1.Columns.Count];
                        row[0] = ""; // Info 컬럼은 공백
                        for (int i = 0; i < Math.Min(tokens.Length, headers.Length); i++)
                            row[i + 1] = tokens[i];

                        dataGridView1.Rows.Add(row);
                    }
                }
            }

            dataGridView1.AutoResizeColumns();
        }
        private void btnExcel_Click(object sender, EventArgs e)
        {
            try
            {
                if (dataGridView1.Rows.Count == 0 || dataGridView1.Columns.Count == 0)
                {
                    MessageBox.Show(this, LanguageManager.Get("msg_no_data_to_export"), LanguageManager.Get("msg_warning"), MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }

                // Create folder on Desktop\EXCEL
                string desktopPath = Environment.GetFolderPath(Environment.SpecialFolder.Desktop);
                string folderPath = Path.Combine(desktopPath, "EXCEL");
                if (!Directory.Exists(folderPath))
                    Directory.CreateDirectory(folderPath);

                // Create file path
                string filePath = Path.Combine(folderPath, $"Export_{DateTime.Now:yyyyMMdd_HHmmss}.xlsx");

                // Create workbook and sheet
                using (var workbook = new ClosedXML.Excel.XLWorkbook())
                {
                    var worksheet = workbook.Worksheets.Add("Sheet1");

                    // Add headers
                    for (int col = 0; col < dataGridView1.Columns.Count; col++)
                    {
                        worksheet.Cell(1, col + 1).Value = dataGridView1.Columns[col].HeaderText;
                    }

                    // Add data
                    for (int row = 0; row < dataGridView1.Rows.Count; row++)
                    {
                        for (int col = 0; col < dataGridView1.Columns.Count; col++)
                        {
                            object value = dataGridView1.Rows[row].Cells[col].Value;
                            worksheet.Cell(row + 2, col + 1).Value = value?.ToString() ?? "";
                        }
                    }

                    workbook.SaveAs(filePath);
                }

                MessageBox.Show(this, LanguageManager.Get("msg_excel_export_completed", filePath), LanguageManager.Get("msg_success"), MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, LanguageManager.Get("msg_excel_export_error", ex.Message), LanguageManager.Get("msg_error"), MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        private void gtnclose_Click(object sender, EventArgs e)
        {
            this.Close();
        }

        private void ApplyLanguage()
        {
            this.Text = LanguageManager.Get("title_search");
            btnSearch.Text = LanguageManager.Get("btn_search");
            btnExcel.Text = LanguageManager.Get("btn_excel");
            gtnclose.Text = LanguageManager.Get("btn_close");
        }
    }
}

