// ADOX를 사용하여 새 .mdb 파일 생성
private static void CreateNewMdbDatabase(string dbPath, string dbFileName)
{
    try
    {
        // ADOX Catalog으로 .mdb 파일 생성
        var cat = new ADOX.Catalog();
        string connString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + dbPath;
        cat.Create(connString);

        // 연결 해제
        System.Runtime.InteropServices.Marshal.ReleaseComObject(cat);
        cat = null;

        System.Diagnostics.Debug.WriteLine($"빈 MDB 파일 생성 완료: {dbPath}");

        // 테이블 생성
        using (var conn = new OleDbConnection(connString))
        {
            conn.Open();

            if (dbFileName.Contains("Part"))
            {
                // Table_Jig 생성
                string createJigTable = @"CREATE TABLE Table_Jig (
                    ID COUNTER PRIMARY KEY,
                    Jig_ID TEXT(50),
                    PartNo TEXT(100),
                    PartName TEXT(100),
                    ioOption TEXT(50),
                    Enable YESNO,
                    Code4M TEXT(50),
                    EoNumber TEXT(50),
                    BarcodeSizeOffset TEXT(50),
                    scanTarget TEXT(255),
                    ImagePath TEXT(255)
                )";
                using (var cmd = new OleDbCommand(createJigTable, conn))
                {
                    cmd.ExecuteNonQuery();
                }
                System.Diagnostics.Debug.WriteLine("Table_Jig 테이블 생성 완료");

                // Table_Seq 생성 (포인트 설정 테이블)
                string createSeqTable = @"CREATE TABLE Table_Seq (
                    ID COUNTER PRIMARY KEY,
                    Jig_ID TEXT(50),
                    Point_ID INTEGER,
                    Value1_Max DOUBLE,
                    Value1_Min DOUBLE,
                    Value2_Max DOUBLE,
                    Value2_Min DOUBLE,
                    Value3_Max DOUBLE,
                    Value3_Min DOUBLE,
                    Value1_Tol DOUBLE,
                    Value2_Tol DOUBLE,
                    Value3_Tol DOUBLE,
                    Value1_Type TEXT(20),
                    Value2_Type TEXT(20),
                    Value3_Type TEXT(20),
                    StartSector INTEGER,
                    EndSector INTEGER,
                    Pass INTEGER,
                    Image_Coord_X INTEGER,
                    Image_Coord_Y INTEGER,
                    Image_Size_X INTEGER,
                    Image_Size_Y INTEGER,
                    graphWidth INTEGER
                )";
                using (var cmd = new OleDbCommand(createSeqTable, conn))
                {
                    cmd.ExecuteNonQuery();
                }
                System.Diagnostics.Debug.WriteLine("Table_Seq 테이블 생성 완료");

                // 기본 JIG 128개 생성
                for (int i = 1; i <= 128; i++)
                {
                    string jigId = i.ToString();
                    string ioOption;
                    if (i <= 64)
                    {
                        var channels = new List<string>();
                        for (int bit = 0; bit < 6; bit++)
                            if ((i & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                        ioOption = string.Join("/", channels);
                    }
                    else
                        ioOption = "";  // 65~128: 미사용
                    string insertJig = $"INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable) VALUES ('{jigId}', '', '', '{ioOption}', True)";
                    using (var cmd = new OleDbCommand(insertJig, conn))
                    {
                        cmd.ExecuteNonQuery();
                    }
                }
                System.Diagnostics.Debug.WriteLine("기본 JIG 128개 생성 완료");
            }
            else if (dbFileName.Contains("Record"))
            {
                // Table_Record 생성
                string createRecordTable = @"CREATE TABLE Table_Record (
                    ID COUNTER PRIMARY KEY,
                    JIG_ID TEXT(50),
                    POINT_ID INTEGER,
                    DateTime DATETIME,
                    AMP_AVG DOUBLE,
                    AMP_MAX DOUBLE,
                    AMP_MIN DOUBLE,
                    VOLT_AVG DOUBLE,
                    VOLT_MAX DOUBLE,
                    VOLT_MIN DOUBLE,
                    FLOW_AVG DOUBLE,
                    FLOW_MAX DOUBLE,
                    FLOW_MIN DOUBLE,
                    TIME_ELAPSED DOUBLE,
                    Result TEXT(10)
                )";
                using (var cmd = new OleDbCommand(createRecordTable, conn))
                {
                    cmd.ExecuteNonQuery();
                }
                System.Diagnostics.Debug.WriteLine("Table_Record 테이블 생성 완료");
            }

            conn.Close();
        }
    }
    catch (Exception ex)
    {
        System.Diagnostics.Debug.WriteLine($"MDB 파일 생성 실패: {ex.Message}");
    }
}

