private static void EnsureJigCount128(string connString)
{
    try
    {
        using (var conn = new OleDbConnection(connString))
        {
            conn.Open();
            var existing = new HashSet<string>();
            using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", conn))
            using (var reader = cmd.ExecuteReader())
            {
                while (reader.Read())
                {
                    string id = reader["Jig_ID"].ToString();
                    if (!string.IsNullOrEmpty(id))
                        existing.Add(id);
                }
            }
            for (int i = 1; i <= 128; i++)
            {
                string jigId = i.ToString();
                if (existing.Contains(jigId)) continue;
                string ioOption;
                if (i <= 64)
                {
                    var channels = new List<string>();
                    for (int bit = 0; bit < 6; bit++)
                        if ((i & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                    ioOption = string.Join("/", channels);
                }
                else
                    ioOption = "";
                using (var cmd = new OleDbCommand("INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable) VALUES (?, ?, ?, ?, ?)", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigId);
                    cmd.Parameters.AddWithValue("?", "");
                    cmd.Parameters.AddWithValue("?", "");
                    cmd.Parameters.AddWithValue("?", ioOption);
                    cmd.Parameters.AddWithValue("?", true);
                    cmd.ExecuteNonQuery();
                }
                existing.Add(jigId);
            }
        }
    }
    catch (Exception ex)
    {
        System.Diagnostics.Debug.WriteLine($"EnsureJigCount128 실패: {ex.Message}");
    }
}

