void SaveResultFromGrid(bool decision)
{
    string baseDir = GlobalValues.GetDataPath();
    string todayPath = Path.Combine(baseDir, DateTime.Now.ToString("yyyy"), DateTime.Now.ToString("MM"), DateTime.Now.ToString("dd"));
    Directory.CreateDirectory(todayPath);

    string serial = "serial";
    string resultTag = (decision) ? "OK" : "NG";
    string timeStamp = DateTime.Now.ToString("yyyyMMdd_HHmmss");
    string fileName = $"{timeStamp}-{resultTag}_{jig.Jig_ID}_{serial}.csv";
    string fullPath = Path.Combine(todayPath, fileName);

    if (!File.Exists(fullPath))
    {
        using (StreamWriter sw = new StreamWriter(fullPath, false, Encoding.UTF8))
        {
            // 1. 컬럼 헤더 저장
            string[] headers = dataGridView1.Columns
                .Cast<DataGridViewColumn>()
                .Select(col => col.HeaderText)
                .ToArray();
            sw.WriteLine(string.Join(",", headers));  // ← 탭 대신 쉼표 사용

            // 2. 행 데이터 저장
            foreach (DataGridViewRow row in dataGridView1.Rows)
            {
                if (row.IsNewRow) continue;

                string[] cells = row.Cells
                    .Cast<DataGridViewCell>()
                    .Select(cell => cell.Value?.ToString()?.Replace(",", "") ?? "")  // 쉼표 제거 (CSV 충돌 방지)
                    .ToArray();

                sw.WriteLine(string.Join(",", cells));  // ← 탭 대신 쉼표 사용
            }
        }
    }
}

/// <summary>
/// 원시데이터 CSV 저장 (RawData + Result)
/// </summary>
void SaveRawDataCsv(string finalResult)
{
    try
    {
        string baseDir = GlobalValues.GetDataPath();
        string rawPath = Path.Combine(baseDir, "RawData", DateTime.Now.ToString("yyyy"), DateTime.Now.ToString("MM"), DateTime.Now.ToString("dd"));
        Directory.CreateDirectory(rawPath);

        string fileName = $"Raw_{jig.Jig_ID}_{rawDataTimestamp}_{finalResult}.csv";
        string fullPath = Path.Combine(rawPath, fileName);

        using (StreamWriter sw = new StreamWriter(fullPath, false, Encoding.UTF8))
        {
            // 각 포인트별 원시데이터 저장
            foreach (var pt in rawDataList)
            {
                sw.WriteLine($"[POINT_{pt.Point}]");
                sw.WriteLine("Time,Amp,Volt,Flow");
                for (int i = 0; i < pt.Time.Count; i++)
                {
                    sw.WriteLine($"{pt.Time[i]:F3},{pt.Amp[i]:F2},{pt.Volt[i]:F2},{pt.Flow[i]:F2}");
                }
                sw.WriteLine();
            }

            // 결과 섹션
            sw.WriteLine("[RESULT]");
            sw.WriteLine("Point,Amp_Avg,Amp_Max,Amp_Min,Volt_Avg,Volt_Max,Volt_Min,Flow_Avg,Flow_Max,Flow_Min,Elapsed,Result");
            foreach (var pt in rawDataList)
            {
                sw.WriteLine($"{pt.Point},{pt.AmpAvg:F2},{pt.AmpMax:F2},{pt.AmpMin:F2},{pt.VoltAvg:F2},{pt.VoltMax:F2},{pt.VoltMin:F2},{pt.FlowAvg:F2},{pt.FlowMax:F2},{pt.FlowMin:F2},{pt.Elapsed:F1},{pt.Result}");
            }

            // 최종 판정
            sw.WriteLine();
            sw.WriteLine($"[FINAL]");
            sw.WriteLine($"JIG_ID,{jig.Jig_ID}");
            sw.WriteLine($"PartNo,{jig.PartNo}");
            sw.WriteLine($"PartName,{jig.PartName}");
            sw.WriteLine($"Timestamp,{rawDataTimestamp}");
            sw.WriteLine($"FinalResult,{finalResult}");
        }

        Logger.Log($"[원시데이터] 저장 완료: {fileName}");
    }
    catch (Exception ex)
    {
        Logger.Log($"[원시데이터] 저장 실패: {ex.Message}");
    }
}

