using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using SkiaSharp;

namespace WeldMonitor3
{
    /// <summary>
    /// 용접 리포트 PDF 생성기 (SkiaSharp 기반)
    /// 사진 샘플과 동일한 포맷: Page1=차트+통계+히스토그램, Page2+=데이터 테이블
    /// </summary>
    public static class ReportGenerator
    {
        // A4 Landscape (points, 72pts/inch)
        const float PW = 842f;
        const float PH = 595f;
        const float ML = 25f;  // 마진 좌
        const float MR = 25f;  // 마진 우
        const float MT = 15f;  // 마진 상
        const float MB = 20f;  // 마진 하
        const int RowsPerDataPage = 45;

        // 폰트
        static SKTypeface GetTypeface(bool bold = false)
        {
            return SKTypeface.FromFamilyName("Malgun Gothic",
                bold ? SKFontStyle.Bold : SKFontStyle.Normal);
        }

        #region 데이터 모델

        public class WeldRecord
        {
            public int WeldNo;
            public string Date;
            public string Time;
            public double Current;
            public double Volt;
            public double Gas;
            public double WeldTime;
            public string Result;
            public double AmpSpecMin, AmpSpecMax;
            public double VoltSpecMin, VoltSpecMax;
            public double GasSpecMin, GasSpecMax;
        }

        public class MeasStats
        {
            public double Max, Min, Average, StdDev, Cp, Cpk;
            public double SpecMin, SpecMax;
            public List<double> Values;
        }

        #endregion

        #region 메인 진입점

        /// <summary>
        /// PDF 리포트 생성. 성공 시 파일 경로 반환, 데이터 없으면 null
        /// </summary>
        public static string Generate(string jigId, DateTime startDate, DateTime endDate)
        {
            var records = LoadRecords(jigId, startDate, endDate);
            if (records.Count == 0) return null;

            // 통계 계산
            var ampStats = CalcStats(
                records.Select(r => r.Current).ToList(),
                records.Where(r => r.AmpSpecMin > 0).Select(r => r.AmpSpecMin).DefaultIfEmpty(0).First(),
                records.Where(r => r.AmpSpecMax > 0).Select(r => r.AmpSpecMax).DefaultIfEmpty(0).First());

            var voltStats = CalcStats(
                records.Select(r => r.Volt).ToList(),
                records.Where(r => r.VoltSpecMin > 0).Select(r => r.VoltSpecMin).DefaultIfEmpty(0).First(),
                records.Where(r => r.VoltSpecMax > 0).Select(r => r.VoltSpecMax).DefaultIfEmpty(0).First());

            var gasStats = CalcStats(
                records.Select(r => r.Gas).ToList(),
                records.Where(r => r.GasSpecMin > 0).Select(r => r.GasSpecMin).DefaultIfEmpty(0).First(),
                records.Where(r => r.GasSpecMax > 0).Select(r => r.GasSpecMax).DefaultIfEmpty(0).First());

            // 출력 경로
            string reportDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Desktop), "Report");
            Directory.CreateDirectory(reportDir);
            string fileName = $"Report_{jigId}_{startDate:yyyyMMdd}_{endDate:yyyyMMdd}_{DateTime.Now:HHmmss}.pdf";
            string outputPath = Path.Combine(reportDir, fileName);

            // PDF 생성
            int dataPages = (int)Math.Ceiling(records.Count / (double)RowsPerDataPage);
            int totalPages = 1 + dataPages;

            using (var stream = new SKFileWStream(outputPath))
            {
                var metadata = new SKDocumentPdfMetadata
                {
                    Title = $"Weld Report - JIG {jigId}",
                    Author = "WeldMonitor3",
                    Creation = DateTime.Now
                };
                using (var doc = SKDocument.CreatePdf(stream, metadata))
                {
                    // Page 1: 리포트 (차트 + 통계 + 히스토그램)
                    DrawReportPage(doc, jigId, startDate, endDate, records, ampStats, voltStats, gasStats, totalPages);

                    // Page 2+: 데이터 테이블
                    for (int p = 0; p < dataPages; p++)
                    {
                        var pageRecs = records.Skip(p * RowsPerDataPage).Take(RowsPerDataPage).ToList();
                        DrawDataPage(doc, jigId, pageRecs, p + 2, totalPages);
                    }

                    doc.Close();
                }
            }

            return outputPath;
        }

        #endregion

        #region 데이터 로드

        static List<WeldRecord> LoadRecords(string jigId, DateTime startDate, DateTime endDate)
        {
            string baseDir = GlobalValues.GetDataPath();
            var records = new List<WeldRecord>();
            int weldNo = 1;

            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
            {
                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
                if (!Directory.Exists(folder)) continue;

                // JIG ID로 필터: 파일명 패턴 *_{jigId}_serial.csv
                var files = Directory.GetFiles(folder, "*.csv")
                    .Where(f => Path.GetFileName(f).Contains($"_{jigId}_"))
                    .OrderBy(f => f)
                    .ToArray();

                foreach (var file in files)
                {
                    try
                    {
                        var lines = File.ReadAllLines(file, Encoding.UTF8);
                        if (lines.Length < 2) continue;

                        // 첫 줄 헤더, 나머지 데이터
                        for (int i = 1; i < lines.Length; i++)
                        {
                            if (string.IsNullOrWhiteSpace(lines[i])) continue;
                            var cols = lines[i].Split(',');
                            if (cols.Length < 13) continue;

                            // 파일명에서 날짜/시간 추출
                            string fName = Path.GetFileNameWithoutExtension(file);
                            string fileDate = "";
                            string fileTime = "";
                            // 파일명: yyyyMMdd_HHmmss-RESULT_JIGID_serial
                            if (fName.Length >= 15)
                            {
                                fileDate = $"{fName.Substring(0, 4)}-{fName.Substring(4, 2)}-{fName.Substring(6, 2)}";
                                fileTime = $"{fName.Substring(9, 2)}:{fName.Substring(11, 2)}:{fName.Substring(13, 2)}";
                            }

                            var rec = new WeldRecord
                            {
                                WeldNo = weldNo++,
                                Date = fileDate,
                                Time = fileTime,
                                Result = SafeStr(cols, 12),
                                WeldTime = SafeDouble(cols, 11)
                            };

                            // 측정값 (Meas 컬럼)
                            rec.Current = SafeDouble(cols, 3);  // A_Meas.
                            rec.Volt = SafeDouble(cols, 6);     // V_Meas.
                            rec.Gas = SafeDouble(cols, 9);      // F_Meas.

                            // 기준값 (Spec 컬럼)
                            rec.AmpSpecMin = SafeDouble(cols, 2);   // A_S.Min
                            rec.AmpSpecMax = SafeDouble(cols, 4);   // A_S.Max
                            rec.VoltSpecMin = SafeDouble(cols, 5);  // V_S.Min
                            rec.VoltSpecMax = SafeDouble(cols, 7);  // V_S.Max
                            rec.GasSpecMin = SafeDouble(cols, 8);   // F_S.Min
                            rec.GasSpecMax = SafeDouble(cols, 10);  // F_S.Max

                            records.Add(rec);
                        }
                    }
                    catch { }
                }
            }

            return records;
        }

        static double SafeDouble(string[] cols, int idx)
        {
            if (idx >= cols.Length) return 0;
            string s = cols[idx].Trim();
            if (s == "-") return 0;
            double.TryParse(s, out double v);
            return v;
        }

        static string SafeStr(string[] cols, int idx)
        {
            return idx < cols.Length ? cols[idx].Trim() : "";
        }

        #endregion

        #region 통계 계산

        static MeasStats CalcStats(List<double> values, double specMin, double specMax)
        {
            var stats = new MeasStats
            {
                Values = values,
                SpecMin = specMin,
                SpecMax = specMax
            };

            if (values.Count == 0) return stats;

            stats.Max = values.Max();
            stats.Min = values.Min();
            stats.Average = values.Average();

            // 표준편차
            double sumSq = values.Sum(v => (v - stats.Average) * (v - stats.Average));
            stats.StdDev = Math.Sqrt(sumSq / values.Count);

            // Cp, Cpk
            if (stats.StdDev > 0 && specMax > specMin)
            {
                stats.Cp = (specMax - specMin) / (6 * stats.StdDev);
                double cpkUpper = (specMax - stats.Average) / (3 * stats.StdDev);
                double cpkLower = (stats.Average - specMin) / (3 * stats.StdDev);
                stats.Cpk = Math.Min(cpkUpper, cpkLower);
            }

            return stats;
        }

        #endregion

        #region Page 1: 리포트 페이지

        static void DrawReportPage(SKDocument doc, string jigId, DateTime startDate, DateTime endDate,
            List<WeldRecord> records, MeasStats ampStats, MeasStats voltStats, MeasStats gasStats, int totalPages)
        {
            var canvas = doc.BeginPage(PW, PH);
            float bodyLeft = ML;
            float bodyRight = PW - MR;
            float bodyWidth = bodyRight - bodyLeft;

            // ── 헤더 영역 ──
            float headerTop = MT;
            float headerH = 80f;
            float headerBot = headerTop + headerH;

            // 헤더 외곽선
            DrawRect(canvas, bodyLeft, headerTop, bodyWidth, headerH);

            // 헤더 세로 구분선
            float col1 = bodyLeft + 250;  // 좌측 정보 | 중앙
            float col2 = bodyRight - 200; // 중앙 | 기준 정보

            DrawLine(canvas, col1, headerTop, col1, headerBot);
            DrawLine(canvas, col2, headerTop, col2, headerBot);

            // 좌측: ROBOT NO, MEASURING DURATION
            DrawText(canvas, "ROBOT NO.", bodyLeft + 5, headerTop + 16, 8f);
            DrawText(canvas, jigId, bodyLeft + 80, headerTop + 16, 12f, true);
            DrawText(canvas, "MEASURING DURATION", bodyLeft + 5, headerTop + 36, 8f);
            DrawText(canvas, $"{startDate:yyyy-MM-dd}~{endDate:yyyy-MM-dd}", bodyLeft + 5, headerTop + 52, 8f);

            // 중앙: 타이틀
            string title = $"{jigId}호기 REPORT";
            using (var paint = CreatePaint(14f, true))
            {
                float tw = paint.MeasureText(title);
                float cx = (col1 + col2) / 2f - tw / 2f;
                canvas.DrawText(title, cx, headerTop + 30, paint);
            }

            // 중앙 하단: COUNT, WELDTIME, MEMO
            float avgWeldTime = records.Count > 0 ? records.Average(r => r.WeldTime) : 0;
            double totalWeldTime = records.Sum(r => r.WeldTime);
            DrawText(canvas, "COUNT", col1 + 10, headerTop + 52, 7f);
            DrawText(canvas, records.Count.ToString(), col1 + 60, headerTop + 52, 8f, true);
            DrawText(canvas, "WELDTIME(sec)", col1 + 100, headerTop + 52, 7f);
            DrawText(canvas, totalWeldTime.ToString("0.0"), col1 + 190, headerTop + 52, 8f, true);
            DrawText(canvas, "MEMO", col1 + 10, headerTop + 68, 7f);

            // 우측: 기준값
            DrawText(canvas, "기준", col2 + 5, headerTop + 14, 7f);
            DrawLine(canvas, col2, headerTop + 20, bodyRight, headerTop + 20);

            float specLabelX = col2 + 5;
            float specValX = col2 + 80;
            DrawText(canvas, "[CURRENT]", specLabelX, headerTop + 34, 7f);
            DrawText(canvas, FormatSpec(ampStats.SpecMin, ampStats.SpecMax), specValX, headerTop + 34, 7f);
            DrawText(canvas, "[VOLT]", specLabelX, headerTop + 50, 7f);
            DrawText(canvas, FormatSpec(voltStats.SpecMin, voltStats.SpecMax), specValX, headerTop + 50, 7f);
            DrawText(canvas, "[GAS]", specLabelX, headerTop + 66, 7f);
            DrawText(canvas, FormatSpec(gasStats.SpecMin, gasStats.SpecMax), specValX, headerTop + 66, 7f);

            // ── 본문 영역 (3행: CURRENT, VOLT, GAS) ──
            float bodyTop = headerBot + 8;
            float bodyBot = PH - MB - 15;
            float bodyH = bodyBot - bodyTop;
            float rowH = bodyH / 3f;

            string[] labels = { "(1) CURRENT(A)", "(2) VOLT(V)", "(3) GAS(ℓ/min)" };
            MeasStats[] statsArr = { ampStats, voltStats, gasStats };

            for (int i = 0; i < 3; i++)
            {
                float rowTop = bodyTop + i * rowH;
                DrawMeasurementRow(canvas, bodyLeft, rowTop, bodyWidth, rowH - 3, labels[i], statsArr[i], records, i);
            }

            // ── 푸터 ──
            DrawText(canvas, $"1/{totalPages}", bodyRight - 30, PH - 8, 8f);

            doc.EndPage();
        }

        static string FormatSpec(double min, double max)
        {
            if (min == 0 && max == 0) return "-";
            return $"{min:0.00} ~ {max:0.00}";
        }

        /// <summary>
        /// 측정 항목 1행 그리기: 라벨 + 시계열 차트 + 통계 테이블 + 히스토그램
        /// </summary>
        static void DrawMeasurementRow(SKCanvas canvas, float x, float y, float w, float h,
            string label, MeasStats stats, List<WeldRecord> records, int measIndex)
        {
            // 외곽선
            DrawRect(canvas, x, y, w, h);

            // 라벨 (세로 텍스트)
            float labelW = 25f;
            DrawLine(canvas, x + labelW, y, x + labelW, y + h);

            canvas.Save();
            canvas.Translate(x + 14, y + h / 2f);
            canvas.RotateDegrees(-90);
            using (var paint = CreatePaint(7.5f, true))
            {
                float tw = paint.MeasureText(label);
                canvas.DrawText(label, -tw / 2f, 0, paint);
            }
            canvas.Restore();

            // 영역 분할: 차트 45%, 통계 20%, 히스토그램 35%
            float contentX = x + labelW + 2;
            float contentW = w - labelW - 4;
            float chartW = contentW * 0.42f;
            float statsW = contentW * 0.22f;
            float histW = contentW * 0.36f;

            float chartX = contentX;
            float statsX = contentX + chartW;
            float histX = statsX + statsW;
            float contentH = h - 4;
            float contentY = y + 2;

            // 구분선
            DrawLine(canvas, statsX, y, statsX, y + h);
            DrawLine(canvas, histX, y, histX, y + h);

            // 시계열 차트
            DrawTimeSeriesChart(canvas, chartX, contentY, chartW - 2, contentH, stats, records, measIndex);

            // 통계 테이블
            DrawStatsTable(canvas, statsX + 2, contentY, statsW - 4, contentH, stats);

            // 히스토그램
            DrawHistogram(canvas, histX + 2, contentY, histW - 4, contentH, stats);
        }

        #endregion

        #region 시계열 차트

        static void DrawTimeSeriesChart(SKCanvas canvas, float x, float y, float w, float h,
            MeasStats stats, List<WeldRecord> records, int measIndex)
        {
            if (stats.Values.Count == 0) return;

            float padL = 35f;  // Y축 라벨
            float padB = 15f;  // X축 라벨
            float padT = 5f;
            float padR = 5f;

            float chartX = x + padL;
            float chartY = y + padT;
            float chartW = w - padL - padR;
            float chartH = h - padT - padB;

            // Y축 범위 계산
            double dataMin = stats.Values.Min();
            double dataMax = stats.Values.Max();
            double yMin = Math.Min(dataMin, stats.SpecMin > 0 ? stats.SpecMin : dataMin) * 0.95;
            double yMax = Math.Max(dataMax, stats.SpecMax > 0 ? stats.SpecMax : dataMax) * 1.05;
            if (yMin == yMax) { yMin -= 1; yMax += 1; }

            // 축선
            using (var axisPaint = new SKPaint { Color = SKColors.Black, StrokeWidth = 0.8f, IsAntialias = true })
            {
                canvas.DrawLine(chartX, chartY, chartX, chartY + chartH, axisPaint);
                canvas.DrawLine(chartX, chartY + chartH, chartX + chartW, chartY + chartH, axisPaint);
            }

            // Y축 눈금 (5개)
            for (int i = 0; i <= 4; i++)
            {
                double val = yMin + (yMax - yMin) * i / 4.0;
                float py = chartY + chartH - (float)((val - yMin) / (yMax - yMin) * chartH);
                DrawText(canvas, val.ToString("0.0"), x + 2, py + 3, 5.5f);

                // 격자선
                using (var gridPaint = new SKPaint { Color = new SKColor(220, 220, 220), StrokeWidth = 0.3f })
                {
                    canvas.DrawLine(chartX, py, chartX + chartW, py, gridPaint);
                }
            }

            // X축 눈금
            int count = stats.Values.Count;
            int xStep = Math.Max(1, count / 6);
            for (int i = 0; i < count; i += xStep)
            {
                float px = chartX + (float)i / Math.Max(1, count - 1) * chartW;
                DrawText(canvas, (i + 1).ToString(), px - 5, chartY + chartH + 11, 5f);
            }
            // 마지막 눈금
            if (count > 1)
                DrawText(canvas, count.ToString(), chartX + chartW - 8, chartY + chartH + 11, 5f);

            // USL/LSL 점선
            if (stats.SpecMax > 0)
            {
                float pyUSL = chartY + chartH - (float)((stats.SpecMax - yMin) / (yMax - yMin) * chartH);
                DrawDashedLine(canvas, chartX, pyUSL, chartX + chartW, pyUSL, SKColors.Black);
            }
            if (stats.SpecMin > 0)
            {
                float pyLSL = chartY + chartH - (float)((stats.SpecMin - yMin) / (yMax - yMin) * chartH);
                DrawDashedLine(canvas, chartX, pyLSL, chartX + chartW, pyLSL, SKColors.Black);
            }

            // 데이터 라인
            using (var dataPaint = new SKPaint
            {
                Color = SKColors.Black,
                StrokeWidth = 1.0f,
                IsAntialias = true,
                Style = SKPaintStyle.Stroke
            })
            {
                var path = new SKPath();
                for (int i = 0; i < count; i++)
                {
                    float px = chartX + (count > 1 ? (float)i / (count - 1) * chartW : chartW / 2);
                    float py = chartY + chartH - (float)((stats.Values[i] - yMin) / (yMax - yMin) * chartH);
                    py = Math.Max(chartY, Math.Min(chartY + chartH, py));

                    if (i == 0) path.MoveTo(px, py);
                    else path.LineTo(px, py);
                }
                canvas.DrawPath(path, dataPaint);
            }
        }

        #endregion

        #region 통계 테이블

        static void DrawStatsTable(SKCanvas canvas, float x, float y, float w, float h, MeasStats stats)
        {
            string[] labels = { "MAX. VALUE", "MIN. VALUE", "AVERAGE", "STD. DEVIATION", "CP", "CPK" };
            string[] values = {
                stats.Max.ToString("0.00"),
                stats.Min.ToString("0.00"),
                stats.Average.ToString("0.00"),
                stats.StdDev.ToString("0.00"),
                stats.Cp.ToString("0.000"),
                stats.Cpk.ToString("0.000")
            };

            float rowH = h / 6f;
            for (int i = 0; i < 6; i++)
            {
                float ry = y + i * rowH;
                // 행 구분선
                if (i > 0)
                    DrawLine(canvas, x, ry, x + w, ry, 0.3f);

                DrawText(canvas, labels[i], x + 3, ry + rowH * 0.65f, 6.5f);
                // 값 우측 정렬
                using (var paint = CreatePaint(7f, true))
                {
                    float vw = paint.MeasureText(values[i]);
                    canvas.DrawText(values[i], x + w - vw - 3, ry + rowH * 0.65f, paint);
                }
            }
        }

        #endregion

        #region 히스토그램

        static void DrawHistogram(SKCanvas canvas, float x, float y, float w, float h, MeasStats stats)
        {
            if (stats.Values.Count < 2) return;

            float padL = 5f;
            float padR = 5f;
            float padT = 5f;
            float padB = 12f;

            float histX = x + padL;
            float histY = y + padT;
            float histW = w - padL - padR;
            float histH = h - padT - padB;

            // 빈 계산 (10개)
            int binCount = Math.Min(15, Math.Max(5, (int)Math.Sqrt(stats.Values.Count)));
            double dataMin = stats.Values.Min();
            double dataMax = stats.Values.Max();
            if (dataMin == dataMax) { dataMin -= 0.5; dataMax += 0.5; }
            double binWidth = (dataMax - dataMin) / binCount;

            int[] bins = new int[binCount];
            foreach (var v in stats.Values)
            {
                int idx = (int)((v - dataMin) / binWidth);
                if (idx >= binCount) idx = binCount - 1;
                if (idx < 0) idx = 0;
                bins[idx]++;
            }

            int maxBin = bins.Max();
            if (maxBin == 0) return;

            // 바 그리기
            float barW = histW / binCount;
            using (var barPaint = new SKPaint { Color = new SKColor(50, 50, 50), Style = SKPaintStyle.Fill })
            using (var barBorder = new SKPaint { Color = SKColors.Black, Style = SKPaintStyle.Stroke, StrokeWidth = 0.5f })
            {
                for (int i = 0; i < binCount; i++)
                {
                    float barH = (float)bins[i] / maxBin * histH;
                    float bx = histX + i * barW;
                    float by = histY + histH - barH;

                    var rect = new SKRect(bx, by, bx + barW, histY + histH);
                    canvas.DrawRect(rect, barPaint);
                    canvas.DrawRect(rect, barBorder);
                }
            }

            // 정규분포 곡선 오버레이
            if (stats.StdDev > 0)
            {
                using (var curvePaint = new SKPaint
                {
                    Color = SKColors.Black,
                    StrokeWidth = 1.2f,
                    IsAntialias = true,
                    Style = SKPaintStyle.Stroke
                })
                {
                    var path = new SKPath();
                    // 정규분포 최댓값 = 1 / (sigma * sqrt(2*pi))
                    double normMax = 1.0 / (stats.StdDev * Math.Sqrt(2 * Math.PI));
                    // 스케일: 바 최대 높이에 맞춤
                    double scale = (double)maxBin / (normMax * binWidth * stats.Values.Count);

                    for (int px = 0; px <= (int)histW; px++)
                    {
                        double val = dataMin + (dataMax - dataMin) * px / histW;
                        double z = (val - stats.Average) / stats.StdDev;
                        double normY = Math.Exp(-0.5 * z * z) / (stats.StdDev * Math.Sqrt(2 * Math.PI));
                        double barHNorm = normY * binWidth * stats.Values.Count / maxBin * histH;
                        barHNorm = Math.Min(barHNorm, histH);

                        float cy = histY + histH - (float)barHNorm;
                        if (px == 0) path.MoveTo(histX + px, cy);
                        else path.LineTo(histX + px, cy);
                    }
                    canvas.DrawPath(path, curvePaint);
                }
            }

            // X축 라벨 (시작, 중간, 끝)
            DrawText(canvas, dataMin.ToString("0.0"), histX - 5, histY + histH + 10, 5f);
            DrawText(canvas, ((dataMin + dataMax) / 2).ToString("0.0"), histX + histW / 2 - 8, histY + histH + 10, 5f);
            DrawText(canvas, dataMax.ToString("0.0"), histX + histW - 15, histY + histH + 10, 5f);
        }

        #endregion

        #region Page 2+: 데이터 테이블

        static void DrawDataPage(SKDocument doc, string jigId, List<WeldRecord> records, int pageNo, int totalPages)
        {
            var canvas = doc.BeginPage(PW, PH);
            float bodyLeft = ML;
            float bodyRight = PW - MR;
            float bodyWidth = bodyRight - bodyLeft;

            // 제목
            string title = $"{jigId}호기";
            using (var paint = CreatePaint(14f, true))
            {
                float tw = paint.MeasureText(title);
                canvas.DrawText(title, (PW - tw) / 2, MT + 18, paint);
            }

            // 테이블 시작
            float tableTop = MT + 30;
            float tableBot = PH - MB - 15;

            // 컬럼 정의
            string[] headers = { "WELD\nNO.", "WELD\nPROCESS", "AC/DC", "DATE", "TIME", "CURRENT\n(A)", "VOLT\n(V)", "GAS\n(ℓ/min)", "WELD\nTIME(sec)", "RESULT" };
            float[] colW = { 40, 60, 45, 80, 65, 75, 65, 65, 65, 55 };

            // 컬럼 너비 합산 → 비율 조정
            float totalW = colW.Sum();
            float scale = bodyWidth / totalW;
            for (int i = 0; i < colW.Length; i++) colW[i] *= scale;

            // 헤더 행
            float headerH = 28f;
            float hx = bodyLeft;
            DrawRect(canvas, bodyLeft, tableTop, bodyWidth, headerH);

            for (int c = 0; c < headers.Length; c++)
            {
                if (c > 0) DrawLine(canvas, hx, tableTop, hx, tableTop + headerH);

                // 다중 줄 헤더
                string[] hLines = headers[c].Split('\n');
                for (int li = 0; li < hLines.Length; li++)
                {
                    using (var hp = CreatePaint(6f, true))
                    {
                        float tw = hp.MeasureText(hLines[li]);
                        float cx = hx + (colW[c] - tw) / 2;
                        float cy = tableTop + 10 + li * 10;
                        canvas.DrawText(hLines[li], cx, cy, hp);
                    }
                }
                hx += colW[c];
            }

            // 데이터 행
            float rowH = Math.Min(12f, (tableBot - tableTop - headerH) / Math.Max(1, records.Count));
            for (int r = 0; r < records.Count; r++)
            {
                float ry = tableTop + headerH + r * rowH;
                if (ry + rowH > tableBot) break;

                // 행 구분선
                DrawLine(canvas, bodyLeft, ry, bodyRight, ry, 0.2f);

                var rec = records[r];
                string[] cells = {
                    rec.WeldNo.ToString(),
                    "ARC",
                    "DC",
                    rec.Date,
                    rec.Time,
                    rec.Current.ToString("0.00"),
                    rec.Volt.ToString("0.00"),
                    rec.Gas.ToString("0.00"),
                    rec.WeldTime.ToString("0.0"),
                    rec.Result
                };

                float cx = bodyLeft;
                for (int c = 0; c < cells.Length; c++)
                {
                    if (c > 0) DrawLine(canvas, cx, ry, cx, ry + rowH, 0.2f);

                    using (var cp = CreatePaint(6f))
                    {
                        float tw = cp.MeasureText(cells[c]);
                        float textX = cx + (colW[c] - tw) / 2;  // 중앙 정렬
                        canvas.DrawText(cells[c], textX, ry + rowH * 0.75f, cp);
                    }
                    cx += colW[c];
                }
            }

            // 테이블 외곽선
            float tableRealBot = tableTop + headerH + records.Count * rowH;
            tableRealBot = Math.Min(tableRealBot, tableBot);
            DrawRect(canvas, bodyLeft, tableTop, bodyWidth, tableRealBot - tableTop);

            // 세로 구분선 (전체)
            hx = bodyLeft;
            for (int c = 0; c < colW.Length; c++)
            {
                if (c > 0) DrawLine(canvas, hx, tableTop, hx, tableRealBot);
                hx += colW[c];
            }

            // 페이지 번호
            DrawText(canvas, $"{pageNo}/{totalPages}", bodyRight - 30, PH - 8, 8f);

            doc.EndPage();
        }

        #endregion

        #region 드로잉 헬퍼

        static SKPaint CreatePaint(float textSize, bool bold = false)
        {
            return new SKPaint
            {
                Color = SKColors.Black,
                TextSize = textSize,
                IsAntialias = true,
                Typeface = GetTypeface(bold)
            };
        }

        static void DrawText(SKCanvas canvas, string text, float x, float y, float size, bool bold = false)
        {
            using (var paint = CreatePaint(size, bold))
            {
                canvas.DrawText(text, x, y, paint);
            }
        }

        static void DrawRect(SKCanvas canvas, float x, float y, float w, float h, float strokeWidth = 0.8f)
        {
            using (var paint = new SKPaint
            {
                Color = SKColors.Black,
                Style = SKPaintStyle.Stroke,
                StrokeWidth = strokeWidth,
                IsAntialias = true
            })
            {
                canvas.DrawRect(x, y, w, h, paint);
            }
        }

        static void DrawLine(SKCanvas canvas, float x1, float y1, float x2, float y2, float strokeWidth = 0.5f)
        {
            using (var paint = new SKPaint
            {
                Color = SKColors.Black,
                StrokeWidth = strokeWidth,
                IsAntialias = true
            })
            {
                canvas.DrawLine(x1, y1, x2, y2, paint);
            }
        }

        static void DrawDashedLine(SKCanvas canvas, float x1, float y1, float x2, float y2, SKColor color)
        {
            using (var paint = new SKPaint
            {
                Color = color,
                StrokeWidth = 0.7f,
                IsAntialias = true,
                PathEffect = SKPathEffect.CreateDash(new float[] { 4, 3 }, 0)
            })
            {
                canvas.DrawLine(x1, y1, x2, y2, paint);
            }
        }

        #endregion
    }
}

