﻿using System;
using System.Collections.Generic;
using System.ComponentModel;
using System.Data;
using System.Drawing;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using System.Windows.Forms;
using System.IO;
using ClosedXML.Excel;

namespace WeldMonitor3
{
    public partial class _FrmSearch : Form
    {
        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
             int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
             int nWidthEllipse, int nHeightEllipse);
        public _FrmSearch()
        {
            InitializeComponent();
            ThemeManager.ApplyDarkTheme(this);
            ApplyLanguage();
            StyleControls();
        }
        private void StyleControls()
        {
            this.BackColor = pColor.Theme.backColor;

            // 패널들 배경 흰색 적용
            Panel[] panels = { panel2 };
            foreach (var pnl in panels)
                pnl.BackColor = pColor.Theme.panelColor;

            // 버튼 스타일 통일화
            foreach (var ctrl in panel2.Controls)
            {
                if (ctrl is Button btn)
                {
                    btn.BackColor = pColor.Theme.buttonColor;
                    btn.ForeColor = pColor.Theme.buttonText;
                    btn.FlatStyle = FlatStyle.Flat;
                    btn.FlatAppearance.BorderSize = 0;
                    // 둥근 모서리

                    btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 15, 15));

                    // 호버 효과
                    btn.MouseEnter += (s, e) => btn.BackColor = pColor.Theme.buttonHover;
                    btn.MouseLeave += (s, e) => btn.BackColor = pColor.Theme.buttonColor;
                }
            }
        }
        private List<string> FindAllCsvFiles(DateTime startDate, DateTime endDate)
        {
            string baseDir = GlobalValues.GetDataPath();
            List<string> resultFiles = new List<string>();

            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
            {
                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
                if (!Directory.Exists(folder)) continue;

                string[] files = Directory.GetFiles(folder, "*.csv");
                resultFiles.AddRange(files);
            }

            return resultFiles;
        }
        private DataTable LoadCsvDataToTable(List<string> files)
        {
            DataTable table = new DataTable();

            bool headerRead = false;

            foreach (var file in files)
            {
                using (StreamReader reader = new StreamReader(file, Encoding.UTF8))
                {
                    string headerLine = reader.ReadLine();
                    if (headerLine == null) continue;

                    string[] headers = headerLine.Split(',');

                    if (!headerRead)
                    {
                        foreach (var h in headers)
                            table.Columns.Add(h);
                        headerRead = true;
                    }

                    while (!reader.EndOfStream)
                    {
                        string line = reader.ReadLine();
                        if (string.IsNullOrWhiteSpace(line)) continue;

                        string[] values = line.Split(',');
