        }
        private List<string> FindAllCsvFiles(DateTime startDate, DateTime endDate)
        {
            string baseDir = GlobalValues.GetDataPath();
            List<string> resultFiles = new List<string>();

            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
            {
                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
                if (!Directory.Exists(folder)) continue;

                string[] files = Directory.GetFiles(folder, "*.csv");
                resultFiles.AddRange(files);
            }

            return resultFiles;
        }
        private DataTable LoadCsvDataToTable(List<string> files)
        {
            DataTable table = new DataTable();

            bool headerRead = false;

            foreach (var file in files)
            {
                using (StreamReader reader = new StreamReader(file, Encoding.UTF8))
                {
                    string headerLine = reader.ReadLine();
                    if (headerLine == null) continue;

                    string[] headers = headerLine.Split(',');

                    if (!headerRead)
                    {
                        foreach (var h in headers)
                            table.Columns.Add(h);
                        headerRead = true;
                    }

                    while (!reader.EndOfStream)
                    {
                        string line = reader.ReadLine();
                        if (string.IsNullOrWhiteSpace(line)) continue;

                        string[] values = line.Split(',');
                        table.Rows.Add(values);
                    }
                }
            }

            return table;
